/* The Pilot Lounge - Airline Transport Pilot question bank.
   Same schema as data/private.js: { id, acs, q, choices[], a (index of correct), src{doc, ref, url, quote} }.
   Facts and quotes trace to FAA public-domain references and the ACS (FAA-S-ACS-11A).
   To extend coverage, add objects to the questions array. */
window.PILOT_LOUNGE = window.PILOT_LOUNGE || {};
window.PILOT_LOUNGE.atp = {
  "title": "Airline Transport Pilot",
  "acsDoc": "FAA-S-ACS-11A",
  "questions": [
    {"id":"atp-001","acs":"ATP.I.G","q":"What is the minimum age to be eligible for an airline transport pilot certificate obtained under the aeronautical experience requirements of 14 CFR 61.159?","choices":["21 years of age","25 years of age","23 years of age"],"a":2,"src":{"doc":"14 CFR 61.153","ref":"Eligibility requirements: General","url":"https://www.ecfr.gov/current/title-14/section-61.153","quote":"For an airline transport pilot certificate obtained under the aeronautical experience requirements of sections 61.159, 61.161, or 61.163, be at least 23 years of age. (14 CFR 61.153(a)(1))"}},
    {"id":"atp-002","acs":"ATP.I.G","q":"Under 14 CFR 61.160, an applicant for an ATP certificate with restricted privileges may apply with a minimum total time as a pilot as low as what figure?","choices":["500 hours with an instrument rating","750 hours as a qualifying U.S. military pilot","1,250 hours with an Associate's degree"],"a":1,"src":{"doc":"14 CFR 61.160","ref":"Aeronautical experience: airplane category restricted privileges","url":"https://www.ecfr.gov/current/title-14/section-61.160","quote":"A U.S. military pilot or former U.S. military pilot may apply for an airline transport pilot certificate with an airplane category multiengine class rating or an airline transport pilot certificate concurrently with a multiengine airplane type rating with a minimum of 750 hours of total time as a pilot. (14 CFR 61.160(a))"}},
    {"id":"atp-003","acs":"ATP.I.G","q":"To be eligible for an ATP certificate, what total time as a pilot is generally required under the standard aeronautical experience rule for an airplane category and class rating?","choices":["1,200 hours of total time","1,000 hours of total time","At least 1,500 hours of total time as a pilot"],"a":2,"src":{"doc":"14 CFR 61.159","ref":"Aeronautical experience: airplane category rating","url":"https://www.ecfr.gov/current/title-14/section-61.159","quote":"A person who is applying for an airline transport pilot certificate with an airplane category and class rating must have at least 1,500 hours of total time as a pilot. (14 CFR 61.159(a))"}},
    {"id":"atp-004","acs":"ATP.I.G","q":"Under the standard ATP airplane experience rule, how much cross-country time is required within the 1,500 hours?","choices":["100 hours of cross-country time","250 hours of cross-country time","500 hours of cross-country time"],"a":2,"src":{"doc":"14 CFR 61.159","ref":"Aeronautical experience: airplane category rating","url":"https://www.ecfr.gov/current/title-14/section-61.159","quote":"A person who is applying for an airline transport pilot certificate with an airplane category and class rating must have at least 1,500 hours of total time as a pilot that includes at least: (1) 500 hours of cross-country time. (14 CFR 61.159(a)(1))"}},
    {"id":"atp-005","acs":"ATP.I.G","q":"How much night flight time is required within the 1,500 hours for the standard ATP airplane experience rule?","choices":["100 hours of night flight time","50 hours of night flight time","25 hours of night flight time"],"a":0,"src":{"doc":"14 CFR 61.159","ref":"Aeronautical experience: airplane category rating","url":"https://www.ecfr.gov/current/title-14/section-61.159","quote":"A person who is applying for an airline transport pilot certificate with an airplane category and class rating must have at least 1,500 hours of total time as a pilot that includes at least: (2) 100 hours of night flight time. (14 CFR 61.159(a)(2))"}},
    {"id":"atp-006","acs":"ATP.I.G","q":"How much instrument flight time, in actual or simulated instrument conditions, is required for the standard ATP airplane experience rule?","choices":["100 hours of instrument flight time","40 hours of instrument flight time","75 hours of instrument flight time"],"a":2,"src":{"doc":"14 CFR 61.159","ref":"Aeronautical experience: airplane category rating","url":"https://www.ecfr.gov/current/title-14/section-61.159","quote":"75 hours of instrument flight time, in actual or simulated instrument conditions. (14 CFR 61.159(a)(4))"}},
    {"id":"atp-007","acs":"ATP.I.E","q":"Before applying for the ATP knowledge test for an airplane multiengine class rating, what must an applicant complete?","choices":["A type rating in a transport-category airplane","A graduation certificate from an authorized training provider certifying completion of the ATP certification training program under 61.156","A minimum of 50 hours of multiengine dual instruction"],"a":1,"src":{"doc":"14 CFR 61.153","ref":"Eligibility requirements: General","url":"https://www.ecfr.gov/current/title-14/section-61.153","quote":"For an airline transport pilot certificate with an airplane category multiengine class rating ... receive a graduation certificate from an authorized training provider certifying completion of the airline transport pilot certification training program specified in section 61.156 before applying for the knowledge test. (14 CFR 61.153(e))"}},
    {"id":"atp-008","acs":"ATP.I.E","q":"How many hours of classroom (academic) instruction must the ATP certification training program (ATP-CTP) include?","choices":["At least 10 hours","At least 30 hours of classroom instruction","At least 20 hours"],"a":1,"src":{"doc":"14 CFR 61.156","ref":"Training requirements: ATP certification training program","url":"https://www.ecfr.gov/current/title-14/section-61.156","quote":"The applicant for the knowledge test must receive at least 30 hours of classroom instruction. (14 CFR 61.156(a))"}},
    {"id":"atp-009","acs":"ATP.I.E","q":"The ATP-CTP academic training must include at least how many hours of instruction on aerodynamics, including high altitude operations?","choices":["At least 14 hours","At least 4 hours","At least 8 hours"],"a":2,"src":{"doc":"14 CFR 61.156","ref":"Training requirements: ATP certification training program","url":"https://www.ecfr.gov/current/title-14/section-61.156","quote":"At least 8 hours of instruction on aerodynamics including high altitude operations. (14 CFR 61.156(a)(1))"}},
    {"id":"atp-010","acs":"ATP.I.E","q":"The ATP-CTP requires FSTD training that includes at least 6 hours in what level of device?","choices":["A basic aviation training device","A Level C or higher full flight simulator representing a multiengine turbine airplane of 40,000 pounds or greater","A Level 4 flight training device of any weight"],"a":1,"src":{"doc":"14 CFR 61.156","ref":"Training requirements: ATP certification training program","url":"https://www.ecfr.gov/current/title-14/section-61.156","quote":"At least 6 hours of training in a Level C or higher full flight simulator qualified under part 60 of this chapter that represents a multiengine turbine airplane with a maximum takeoff weight of 40,000 pounds or greater. (14 CFR 61.156(b)(1))"}},
    {"id":"atp-011","acs":"ATP.I.F","q":"The ATP aeronautical knowledge areas specifically include crew resource management. What does that area include?","choices":["Engine overhaul procedures","Aircraft maintenance recordkeeping","Crew communication and coordination"],"a":2,"src":{"doc":"14 CFR 61.155","ref":"Aeronautical knowledge","url":"https://www.ecfr.gov/current/title-14/section-61.155","quote":"Crew resource management to include crew communication and coordination. (14 CFR 61.155(c)(13))"}},
    {"id":"atp-012","acs":"ATP.I.C","q":"Which aeronautical knowledge area is specifically listed for the ATP knowledge test regarding low-level wind hazards?","choices":["Windshear and microburst awareness, identification, and avoidance","Density altitude correction tables","Crosswind component computation"],"a":0,"src":{"doc":"14 CFR 61.155","ref":"Aeronautical knowledge","url":"https://www.ecfr.gov/current/title-14/section-61.155","quote":"Windshear and microburst awareness, identification, and avoidance. (14 CFR 61.155(c)(6))"}},
    {"id":"atp-013","acs":"ATP.I.A","q":"On the airspeed indicator of most multiengine airplanes, what does the blue radial line (VYSE) represent?","choices":["The minimum control speed","The never-exceed speed","Best rate of climb speed with one engine inoperative"],"a":2,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Ch 13 Transition to Multiengine Airplanes","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/airplane_handbook/14_afh_ch13.pdf","quote":"VYSE - best rate of climb speed with OEI. Marked with a blue radial line on most airspeed indicators. (FAA-H-8083-3C, Ch 13)"}},
    {"id":"atp-014","acs":"ATP.I.B","q":"On the airspeed indicator of most multiengine airplanes, what does the red radial line represent?","choices":["Maneuvering speed","Best single-engine glide speed","The minimum control speed, VMC"],"a":2,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Ch 13 Transition to Multiengine Airplanes","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/airplane_handbook/14_afh_ch13.pdf","quote":"VMC is a speed established by the manufacturer, published in the AFM/POH, and marked on most airspeed indicators with a red radial line. (FAA-H-8083-3C, Ch 13)"}},
    {"id":"atp-015","acs":"ATP.I.B","q":"In aircraft certification, VMC is determined with the airplane at what maximum angle of bank?","choices":["A maximum of 10 degrees angle of bank","Wings level only","A maximum of 5 degrees angle of bank"],"a":2,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Ch 13 Transition to Multiengine Airplanes","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/airplane_handbook/14_afh_ch13.pdf","quote":"It is possible to maintain control of the airplane with that engine still inoperative and then maintain straight flight at the same speed with an angle of bank not more than 5 degrees. (FAA-H-8083-3C, Ch 13)"}},
    {"id":"atp-016","acs":"ATP.I.B","q":"Is the airplane required to be capable of climbing at VMC?","choices":["Yes, but only with the gear retracted","No, VMC only addresses directional control and does not guarantee a climb","Yes, VMC always guarantees a positive rate of climb"],"a":1,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Ch 13 Transition to Multiengine Airplanes","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/airplane_handbook/14_afh_ch13.pdf","quote":"There is no requirement under either determination that the airplane be capable of climbing at this airspeed. VMC only addresses directional control. (FAA-H-8083-3C, Ch 13)"}},
    {"id":"atp-017","acs":"ATP.I.D","q":"What term describes the Mach number at which some portion of the airflow over the wing first equals Mach 1.0?","choices":["The critical Mach number","The maximum operating Mach number (MMO)","The drag divergence number"],"a":0,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Ch 16 Transition to Jet-Powered Airplanes","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/airplane_handbook/17_afh_ch16.pdf","quote":"The Mach number at which some portion of the airflow over the wing first equals Mach 1.0 is termed the critical Mach number (MCR). (FAA-H-8083-3C, Ch 16)"}},
    {"id":"atp-018","acs":"ATP.I.D","q":"As airspeed increases and the shock wave moves aft, the wing's center of pressure moves aft, causing what tendency known as Mach tuck?","choices":["A nose-down pitching tendency","A nose-up pitching tendency","An uncommanded roll"],"a":0,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Ch 16 Transition to Jet-Powered Airplanes","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/airplane_handbook/17_afh_ch16.pdf","quote":"With increased speed and the aft movement of the shock wave, the wing's center of pressure moves aft causing the start of a nose-down tendency or 'tuck.' (FAA-H-8083-3C, Ch 16)"}},
    {"id":"atp-019","acs":"ATP.I.D","q":"What is the region of the flight envelope where any increase in angle of attack at MMO would cause buffeting, bounded by low-speed and high-speed Mach buffet?","choices":["The maneuvering envelope","The service ceiling","Coffin corner"],"a":2,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Ch 16 Transition to Jet-Powered Airplanes","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/airplane_handbook/17_afh_ch16.pdf","quote":"The altitude at which an airplane flying at MMO would experience buffeting with any increase in AOA determines the absolute or aerodynamic ceiling. ... This region of the airplane's flight envelope is known as 'coffin corner.' (FAA-H-8083-3C, Ch 16)"}},
    {"id":"atp-020","acs":"ATP.I.D","q":"What is the underlying cause of Mach buffet?","choices":["An aerodynamic stall at low speed","Airflow separation on the upper surface of a wing behind a shock wave","Propeller wash interacting with the tail"],"a":1,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Ch 16 Transition to Jet-Powered Airplanes","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/airplane_handbook/17_afh_ch16.pdf","quote":"Mach buffet arises when airflow separates on the upper surface of a wing behind a shock wave. (FAA-H-8083-3C, Ch 16)"}},
    {"id":"atp-021","acs":"ATP.I.D","q":"On a swept wing, where does a natural tendency to stall first occur?","choices":["At the wing root","At the wing tips","Along the trailing edge evenly"],"a":1,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Ch 16 Transition to Jet-Powered Airplanes","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/airplane_handbook/17_afh_ch16.pdf","quote":"If a simple, straight-wing airplane's airfoil is swept, a natural tendency arises that it will stall at the wing tips first. This is because the boundary layer tends to flow spanwise toward the tips. (FAA-H-8083-3C, Ch 16)"}},
    {"id":"atp-022","acs":"ATP.II.A","q":"Among the ATP-CTP academic topics required for air carrier operations, which item addresses required onboard equipment lists?","choices":["Aircraft logbook entries","Crew scheduling software","Minimum equipment list/configuration deviation list"],"a":2,"src":{"doc":"14 CFR 61.156","ref":"Training requirements: ATP certification training program","url":"https://www.ecfr.gov/current/title-14/section-61.156","quote":"At least 14 hours of instruction on air carrier operations, including the following areas: ... (v) Minimum equipment list/configuration deviation list. (14 CFR 61.156(a)(3)(v))"}},
    {"id":"atp-023","acs":"ATP.II.E","q":"Among the air carrier operations academic topics in the ATP-CTP, which is specifically required regarding standardized procedures?","choices":["Checklist philosophy","Fuel jettison procedures","Cargo loading sequence"],"a":0,"src":{"doc":"14 CFR 61.156","ref":"Training requirements: ATP certification training program","url":"https://www.ecfr.gov/current/title-14/section-61.156","quote":"At least 14 hours of instruction on air carrier operations, including the following areas: ... (iii) Checklist philosophy. (14 CFR 61.156(a)(3)(iii))"}},
    {"id":"atp-024","acs":"ATP.III.A","q":"For a jet-powered airplane, what is V1?","choices":["The maximum structural cruising speed","The critical engine failure speed or takeoff decision speed","The best angle-of-climb speed"],"a":1,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Ch 16 Transition to Jet-Powered Airplanes","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/airplane_handbook/17_afh_ch16.pdf","quote":"V1 - critical engine failure speed or takeoff decision speed. It is the speed at which the pilot is to continue the takeoff in the event of an engine failure or other serious emergency. (FAA-H-8083-3C, Ch 16)"}},
    {"id":"atp-025","acs":"ATP.III.A","q":"For a jet-powered airplane, what does VR represent?","choices":["Reverse-thrust cutoff speed","Rotation speed, at which the rotation of the airplane is initiated to takeoff attitude","Reference landing speed"],"a":1,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Ch 16 Transition to Jet-Powered Airplanes","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/airplane_handbook/17_afh_ch16.pdf","quote":"VR - rotation speed, or speed at which the rotation of the airplane is initiated to takeoff attitude. This speed cannot be less than V1 or less than 1.05 x VMCA. (FAA-H-8083-3C, Ch 16)"}},
    {"id":"atp-026","acs":"ATP.III.A","q":"For a jet-powered airplane, what is V2?","choices":["The takeoff safety speed, at which the required one-engine-inoperative climb performance can be achieved","The maximum gear-extension speed","The landing reference speed"],"a":0,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Ch 16 Transition to Jet-Powered Airplanes","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/airplane_handbook/17_afh_ch16.pdf","quote":"V2 - takeoff safety speed, or a referenced airspeed obtained after lift-off at which the required one-engine-inoperative climb performance can be achieved. (FAA-H-8083-3C, Ch 16)"}},
    {"id":"atp-027","acs":"ATP.VII.I","q":"What is the accelerate-stop distance for a multiengine airplane?","choices":["The runway length required to accelerate to a specified speed, experience an engine failure, and bring the airplane to a complete stop","The distance to accelerate to liftoff and climb to 50 feet","The total runway plus stopway available"],"a":0,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Ch 13 Transition to Multiengine Airplanes","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/airplane_handbook/14_afh_ch13.pdf","quote":"Accelerate-stop distance is the runway length required to accelerate to a specified speed (either VR or VLOF, as specified by the manufacturer), experience an engine failure, and bring the airplane to a complete stop. (FAA-H-8083-3C, Ch 13)"}},
    {"id":"atp-028","acs":"ATP.III.A","q":"What is the accelerate-go distance for a multiengine airplane?","choices":["The horizontal distance required to continue the takeoff and climb to 50 feet, assuming an engine failure at VR or VLOF","The distance from brake release to rotation","The distance to decelerate from V2 to a stop"],"a":0,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Ch 13 Transition to Multiengine Airplanes","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/airplane_handbook/14_afh_ch13.pdf","quote":"Accelerate-go distance is the horizontal distance required to continue the takeoff and climb to 50 feet, assuming an engine failure at VR or VLOF, as specified by the manufacturer. (FAA-H-8083-3C, Ch 13)"}},
    {"id":"atp-029","acs":"ATP.V.B","q":"At what point does a wing stall, regardless of airspeed, weight, or attitude?","choices":["When airspeed drops below a fixed published number","When the critical angle of attack is exceeded","Only when power is reduced to idle"],"a":1,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Ch 5 Maintaining Aircraft Control: UPRT","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/airplane_handbook/06_afh_ch5.pdf","quote":"It is important for the pilot to understand that a stall is the result of exceeding the critical AOA, not of insufficient airspeed. ... Therefore, it is possible to stall the wing at any airspeed, at any flight attitude, and at any power setting. (FAA-H-8083-3C, Ch 5)"}},
    {"id":"atp-030","acs":"ATP.V.A","q":"Does the critical angle of attack at which a given airplane stalls change with weight, bank angle, or density altitude?","choices":["No, a given aircraft always stalls at the same AOA regardless of those factors","Yes, the critical AOA increases with weight","Yes, the critical AOA decreases at high density altitude"],"a":0,"src":{"doc":"FAA-H-8083-25C","ref":"Pilot's Handbook of Aeronautical Knowledge, Ch 5 Aerodynamics of Flight","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/phak/07_phak_ch5.pdf","quote":"A given aircraft always stalls at the same AOA regardless of airspeed, weight, load factor, or density altitude. (FAA-H-8083-25C, Ch 5)"}},
    {"id":"atp-031","acs":"ATP.IV.C","q":"On a swept wing, the tendency for tip stall is greatest under what condition?","choices":["At very low angles of attack only","When wing sweep and taper are combined","When the wing has no taper"],"a":1,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Ch 16 Transition to Jet-Powered Airplanes","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/airplane_handbook/17_afh_ch16.pdf","quote":"The tendency for tip stall allowing the center of lift to move forward is greatest when wing sweep and taper are combined. (FAA-H-8083-3C, Ch 16)"}},
    {"id":"atp-032","acs":"ATP.VI.J","q":"What turn direction defines a standard holding pattern?","choices":["Either, at pilot discretion","Left turns","Right turns"],"a":2,"src":{"doc":"AIM","ref":"Aeronautical Information Manual 5-3-8, Holding","url":"https://www.faa.gov/air_traffic/publications/atpubs/aim_html/chap5_section_3.html","quote":"Standard Pattern. Right turns. (AIM 5-3-8)"}},
    {"id":"atp-033","acs":"ATP.VI.J","q":"What is the maximum holding airspeed for all aircraft at 14,001 feet and above?","choices":["200 KIAS","265 KIAS","230 KIAS"],"a":1,"src":{"doc":"AIM","ref":"Aeronautical Information Manual 5-3-8, Holding (TBL 5-3-2)","url":"https://www.faa.gov/air_traffic/publications/atpubs/aim_html/chap5_section_3.html","quote":"All aircraft may hold at the following altitudes and maximum holding airspeeds: ... 14,001' and above, 265 KIAS. (AIM 5-3-8)"}},
    {"id":"atp-034","acs":"ATP.VI.J","q":"What is the maximum holding airspeed for all aircraft from the minimum holding altitude up to 6,000 feet?","choices":["265 KIAS","230 KIAS","200 KIAS"],"a":2,"src":{"doc":"AIM","ref":"Aeronautical Information Manual 5-3-8, Holding (TBL 5-3-2)","url":"https://www.faa.gov/air_traffic/publications/atpubs/aim_html/chap5_section_3.html","quote":"All aircraft may hold at the following altitudes and maximum holding airspeeds: MHA - 6,000', 200 KIAS. (AIM 5-3-8)"}},
    {"id":"atp-035","acs":"ATP.VI.J","q":"What is the maximum holding airspeed for all aircraft from 6,001 feet to 14,000 feet?","choices":["230 KIAS","265 KIAS","200 KIAS"],"a":0,"src":{"doc":"AIM","ref":"Aeronautical Information Manual 5-3-8, Holding (TBL 5-3-2)","url":"https://www.faa.gov/air_traffic/publications/atpubs/aim_html/chap5_section_3.html","quote":"All aircraft may hold at the following altitudes and maximum holding airspeeds: 6,001' - 14,000', 230 KIAS. (AIM 5-3-8)"}},
    {"id":"atp-036","acs":"ATP.I.A","q":"Wake turbulence wingtip vortices are strongest when the generating aircraft is in what condition?","choices":["Heavy, dirty, and fast","Light, dirty, and fast","Heavy, clean, and slow"],"a":2,"src":{"doc":"AIM","ref":"Aeronautical Information Manual 7-4-3, Vortex Strength","url":"https://www.faa.gov/air_traffic/publications/atpubs/aim_html/chap7_section_4.html","quote":"The greatest vortex strength occurs when the generating aircraft is HEAVY, CLEAN, and SLOW. (AIM 7-4-3)"}},
    {"id":"atp-037","acs":"ATP.I.A","q":"How does wingtip vortex strength change with the generating aircraft's operating weight and speed?","choices":["It is unaffected by weight and speed","It decreases with an increase in weight","It increases with an increase in weight or a decrease in speed"],"a":2,"src":{"doc":"AIM","ref":"Aeronautical Information Manual 7-4-3, Vortex Strength","url":"https://www.faa.gov/air_traffic/publications/atpubs/aim_html/chap7_section_4.html","quote":"The vortex strength from an aircraft increases proportionately to an increase in operating weight or a decrease in aircraft speed. (AIM 7-4-3)"}},
    {"id":"atp-038","acs":"ATP.VII.A","q":"How strong can the downdrafts in a microburst be?","choices":["No more than 2,000 feet per minute","As strong as 6,000 feet per minute","As strong as 1,000 feet per minute"],"a":1,"src":{"doc":"AIM","ref":"Aeronautical Information Manual 7-1-24, Microbursts","url":"https://www.faa.gov/air_traffic/publications/atpubs/aim_html/chap7_section_1.html","quote":"The downdrafts can be as strong as 6,000 feet per minute. (AIM 7-1-24)"}},
    {"id":"atp-039","acs":"ATP.VII.A","q":"In a microburst, horizontal winds near the surface can be as strong as 45 knots, resulting in what total wind shear for a traversing aircraft?","choices":["A 45 knot shear","A 60 knot shear","A 90 knot shear from headwind to tailwind"],"a":2,"src":{"doc":"AIM","ref":"Aeronautical Information Manual 7-1-24, Microbursts","url":"https://www.faa.gov/air_traffic/publications/atpubs/aim_html/chap7_section_1.html","quote":"Horizontal winds near the surface can be as strong as 45 knots resulting in a 90 knot shear (headwind to tailwind change for a traversing aircraft) across the microburst. (AIM 7-1-24)"}},
    {"id":"atp-040","acs":"ATP.VII.A","q":"During an inadvertent takeoff into a microburst, in what sequence does the aircraft typically encounter the wind?","choices":["A tailwind, then a headwind, then calm","A steady crosswind throughout","A performance-increasing headwind, then performance-decreasing downdrafts, then a rapidly increasing tailwind"],"a":2,"src":{"doc":"FAA-H-8083-25C","ref":"Pilot's Handbook of Aeronautical Knowledge, Ch 12","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/phak","quote":"During an inadvertent takeoff into a microburst, the plane may first experience a performance-increasing headwind, followed by performance-decreasing downdrafts, followed by a rapidly increasing tailwind. (FAA-H-8083-25C, Ch 12)"}},
    {"id":"atp-041","acs":"ATP.VI.B","q":"Unless otherwise specified, what minimum climb gradient is assumed for obstacle clearance on a standard instrument departure?","choices":["200 feet per nautical mile","152 feet per nautical mile","400 feet per nautical mile"],"a":0,"src":{"doc":"FAA-H-8083-16B","ref":"Instrument Procedures Handbook, Ch 1 Departure Procedures","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/instrument_procedures_handbook/FAA-H-8083-16B_Chapter_1.pdf","quote":"Required obstacle clearance for all departures, including diverse, is based on the pilot crossing the departure end of the runway (DER) at least 35 feet above the DER elevation, climbing to 400 feet above the DER elevation before making the initial turn, and maintaining a minimum climb gradient of 200 ft/NM. (FAA-H-8083-16B, Ch 1)"}},
    {"id":"atp-042","acs":"ATP.VI.E","q":"On a precision approach, what is a Decision Altitude (DA)?","choices":["The altitude at which the autopilot must be disconnected","A specified altitude at which a missed approach must be initiated if the required visual reference has not been established","The lowest altitude to which descent is authorized on a nonprecision final"],"a":1,"src":{"doc":"FAA-H-8083-16B","ref":"Instrument Procedures Handbook, Ch 4 Approaches","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/instrument_procedures_handbook/FAA-H-8083-16B_Chapter_4.pdf","quote":"DA - a specified altitude in the precision approach at which a missed approach must be initiated if the required visual reference to continue the approach has not been established. (FAA-H-8083-16B, Ch 4)"}},
    {"id":"atp-043","acs":"ATP.VI.D","q":"What is the Minimum Descent Altitude (MDA) on a nonprecision approach?","choices":["The minimum en route altitude","The lowest altitude to which descent is authorized on final approach where no electronic glideslope is provided","The altitude at which the missed approach is always begun"],"a":1,"src":{"doc":"FAA-H-8083-16B","ref":"Instrument Procedures Handbook, Ch 4 Approaches","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/instrument_procedures_handbook/FAA-H-8083-16B_Chapter_4.pdf","quote":"MDA - the lowest altitude, expressed in feet MSL, to which descent is authorized on final approach or during circle-to-land maneuvering in execution of a standard instrument approach procedure (SIAP) where no electronic glideslope is provided. (FAA-H-8083-16B, Ch 4)"}},
    {"id":"atp-044","acs":"ATP.VI.E","q":"On a precision approach, where is the missed approach point (MAP)?","choices":["At the runway threshold","At the final approach fix","The point at which the aircraft reaches the DA or DH while on the glideslope/glidepath"],"a":2,"src":{"doc":"FAA-H-8083-16B","ref":"Instrument Procedures Handbook, Ch 4 Approaches","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/instrument_procedures_handbook/FAA-H-8083-16B_Chapter_4.pdf","quote":"For a precision approach, the MAP is the point at which the aircraft reaches the DA or DH while on the glideslope/glidepath. (FAA-H-8083-16B, Ch 4)"}},
    {"id":"atp-045","acs":"ATP.VI.F","q":"Under 14 CFR 91.175, before descending below DA/DH or MDA, what must be true about flight visibility?","choices":["It must be reported by the tower as VFR","It must be not less than the visibility prescribed in the standard instrument approach being used","It must be at least 3 statute miles regardless of the approach"],"a":1,"src":{"doc":"14 CFR 91.175","ref":"Takeoff and landing under IFR","url":"https://www.ecfr.gov/current/title-14/section-91.175","quote":"The flight visibility is not less than the visibility prescribed in the standard instrument approach being used. (14 CFR 91.175(c)(2))"}},
    {"id":"atp-046","acs":"ATP.VI.I","q":"Under 14 CFR 91.175(c)(1), to continue below DA/DH or MDA the aircraft must be in a position from which what can be done?","choices":["A circling approach to any runway","An immediate go-around at full power","A descent to a landing on the intended runway at a normal rate of descent using normal maneuvers"],"a":2,"src":{"doc":"14 CFR 91.175","ref":"Takeoff and landing under IFR","url":"https://www.ecfr.gov/current/title-14/section-91.175","quote":"The aircraft is continuously in a position from which a descent to a landing on the intended runway can be made at a normal rate of descent using normal maneuvers. (14 CFR 91.175(c)(1))"}},
    {"id":"atp-047","acs":"ATP.VI.F","q":"Using the approach light system as the only visual reference under 91.175, a pilot may not descend below what height above touchdown zone elevation unless the red terminating bars or red side row bars are also visible?","choices":["50 feet","100 feet","200 feet"],"a":1,"src":{"doc":"14 CFR 91.175","ref":"Takeoff and landing under IFR","url":"https://www.ecfr.gov/current/title-14/section-91.175","quote":"The pilot may not descend below 100 feet above the touchdown zone elevation using the approach lights as a reference unless the red terminating bars or the red side row bars are also distinctly visible and identifiable. (14 CFR 91.175(c)(3)(i))"}},
    {"id":"atp-048","acs":"ATP.VI.A","q":"When operating at or above 18,000 feet MSL, to what value must the altimeter be set?","choices":["29.92 inches of mercury","The current local altimeter setting","The field elevation pressure"],"a":0,"src":{"doc":"14 CFR 91.121","ref":"Altimeter settings","url":"https://www.ecfr.gov/current/title-14/section-91.121","quote":"Each person operating an aircraft shall maintain the cruising altitude or flight level of that aircraft ... by reference to an altimeter that is set, when operating ... At or above 18,000 feet MSL, to 29.92 Hg. (14 CFR 91.121(a)(2))"}},
    {"id":"atp-049","acs":"ATP.VI.A","q":"When operating below 18,000 feet MSL, the altimeter must be set to the current reported altimeter setting of a station along the route within what distance of the aircraft?","choices":["Within 50 nautical miles","Within 100 nautical miles","Within 25 nautical miles"],"a":1,"src":{"doc":"14 CFR 91.121","ref":"Altimeter settings","url":"https://www.ecfr.gov/current/title-14/section-91.121","quote":"Below 18,000 feet MSL, to ... The current reported altimeter setting of a station along the route and within 100 nautical miles of the aircraft. (14 CFR 91.121(a)(1)(i))"}},
    {"id":"atp-050","acs":"ATP.VI.C","q":"Within Reduced Vertical Separation Minimum (RVSM) airspace, what vertical separation does ATC apply between FL290 and FL410 inclusive?","choices":["500 feet","2,000 feet","1,000 feet"],"a":2,"src":{"doc":"14 CFR Part 91 Appendix G","ref":"Operations in RVSM Airspace","url":"https://www.ecfr.gov/current/title-14/part-91/appendix-Appendix%20G%20to%20Part%2091","quote":"Within RVSM airspace, air traffic control (ATC) separates aircraft by a minimum of 1,000 feet vertically between FL 290 and FL 410 inclusive. (14 CFR Part 91, Appendix G)"}},
    {"id":"atp-051","acs":"ATP.VI.C","q":"To operate in RVSM airspace, what authorization is required in addition to meeting Appendix G standards?","choices":["No additional authorization is needed","The operator must be authorized by the Administrator or the country of registry","Only a current biennial flight review"],"a":1,"src":{"doc":"14 CFR 91.180","ref":"Operations within RVSM airspace","url":"https://www.ecfr.gov/current/title-14/section-91.180","quote":"No person may operate a civil aircraft in airspace designated as Reduced Vertical Separation Minimum (RVSM) airspace unless ... The operator is authorized by the Administrator or the country of registry to conduct such operations. (14 CFR 91.180(a)(2))"}},
    {"id":"atp-052","acs":"ATP.VII.D","q":"During a one-engine-inoperative VMC demonstration, what is the pilot training to recognize and recover from?","choices":["A high-altitude Mach buffet","An aerodynamic stall at the wing root","Loss of directional control associated with the red radial indicated airspeed"],"a":2,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Ch 13 Transition to Multiengine Airplanes","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/airplane_handbook/14_afh_ch13.pdf","quote":"Pilots also learn to recognize and recover from loss of directional control associated with the red radial indicated airspeed by performing a VMC demonstration. (FAA-H-8083-3C, Ch 13)"}},
    {"id":"atp-053","acs":"ATP.I.G","q":"Under what condition may an ATP applicant credit a maximum of 25 hours of training in a full flight simulator toward the 50 hours required in the class of airplane for the rating sought?","choices":["When accomplished as part of an approved training course under parts 121, 135, 141, or 142","When logged in any aviation training device","When flown solo in actual instrument conditions"],"a":0,"src":{"doc":"14 CFR 61.159","ref":"Aeronautical experience: airplane category rating","url":"https://www.ecfr.gov/current/title-14/section-61.159","quote":"A maximum of 25 hours of training in a full flight simulator representing the class of airplane for the rating sought may be credited toward the flight time requirement of this paragraph if the training was accomplished as part of an approved training course in parts 121, 135, 141, or 142 of this chapter. (14 CFR 61.159(a)(3))"}},
    {"id":"atp-054","acs":"ATP.I.G","q":"How many hours of flight time in an airplane as pilot in command (or qualifying SIC) are required for the standard ATP airplane experience rule?","choices":["250 hours","500 hours","100 hours"],"a":0,"src":{"doc":"14 CFR 61.159","ref":"Aeronautical experience: airplane category rating","url":"https://www.ecfr.gov/current/title-14/section-61.159","quote":"250 hours of flight time in an airplane as a pilot in command, or as second in command performing the duties of pilot in command while under the supervision of a pilot in command, or any combination thereof. (14 CFR 61.159(a)(5))"}},
    {"id":"atp-055","acs":"ATP.I.G","q":"A person who has performed at least 20 night takeoffs and landings to a full stop may substitute each additional one for one hour of night flight time, up to what maximum credited in this manner?","choices":["Not more than 10 hours","Not more than 50 hours","Not more than 25 hours"],"a":2,"src":{"doc":"14 CFR 61.159","ref":"Aeronautical experience: airplane category rating","url":"https://www.ecfr.gov/current/title-14/section-61.159","quote":"A person who has performed at least 20 night takeoffs and landings to a full stop may substitute each additional night takeoff and landing to a full stop for 1 hour of night flight time ... however, not more than 25 hours of night flight time may be credited in this manner. (14 CFR 61.159(b))"}},
    {"id":"atp-056","acs":"ATP.I.G","q":"A person who holds an airline transport pilot certificate is entitled to the privileges of what other certificate?","choices":["A flight instructor certificate","A commercial pilot certificate with an instrument rating","A private pilot certificate only"],"a":1,"src":{"doc":"14 CFR 61.167","ref":"Airline transport pilot privileges and limitations","url":"https://www.ecfr.gov/current/title-14/section-61.167","quote":"A person who holds an airline transport pilot certificate is entitled to the same privileges as a person who holds a commercial pilot certificate with an instrument rating. (14 CFR 61.167(a)(1))"}},
    {"id":"atp-057","acs":"ATP.I.F","q":"When instructing under the privileges of 61.167, an ATP may not instruct in aircraft, flight simulators, and flight training devices for more than how many hours in any 24-consecutive-hour period?","choices":["8 hours","12 hours","10 hours"],"a":0,"src":{"doc":"14 CFR 61.167","ref":"Airline transport pilot privileges and limitations","url":"https://www.ecfr.gov/current/title-14/section-61.167","quote":"An airline transport pilot may not instruct in aircraft, flight simulators, and flight training devices under this section ... For more than 8 hours in any 24-consecutive-hour period. (14 CFR 61.167(a)(3)(i))"}},
    {"id":"atp-058","acs":"ATP.I.E","q":"For a domestic part 121 operation, no flight crewmember may accept an assignment if total flight time in all commercial flying will exceed how many hours in any calendar year?","choices":["1,200 hours","1,000 hours","1,400 hours"],"a":1,"src":{"doc":"14 CFR 121.471","ref":"Flight time limitations and rest requirements: All flight crewmembers","url":"https://www.ecfr.gov/current/title-14/section-121.471","quote":"No certificate holder conducting domestic operations may schedule any flight crewmember ... if that crewmember's total flight time in all commercial flying will exceed - (1) 1,000 hours in any calendar year. (14 CFR 121.471(a)(1))"}},
    {"id":"atp-059","acs":"ATP.I.E","q":"Under 14 CFR 121.471, what is the maximum scheduled flight time for a domestic flight crewmember in any calendar month?","choices":["120 hours","85 hours","100 hours"],"a":2,"src":{"doc":"14 CFR 121.471","ref":"Flight time limitations and rest requirements: All flight crewmembers","url":"https://www.ecfr.gov/current/title-14/section-121.471","quote":"No certificate holder conducting domestic operations may schedule any flight crewmember ... if that crewmember's total flight time in all commercial flying will exceed - ... (2) 100 hours in any calendar month. (14 CFR 121.471(a)(2))"}},
    {"id":"atp-060","acs":"ATP.I.E","q":"Under 14 CFR 121.471, a domestic certificate holder must relieve each flight crewmember from all further duty for at least how long during any 7 consecutive days?","choices":["At least 18 consecutive hours","At least 36 consecutive hours","At least 24 consecutive hours"],"a":2,"src":{"doc":"14 CFR 121.471","ref":"Flight time limitations and rest requirements: All flight crewmembers","url":"https://www.ecfr.gov/current/title-14/section-121.471","quote":"Each certificate holder conducting domestic operations shall relieve each flight crewmember engaged in scheduled air transportation from all further duty for at least 24 consecutive hours during any 7 consecutive days. (14 CFR 121.471(d))"}},
    {"id":"atp-061","acs":"ATP.II.A","q":"Among the air carrier operations academic topics required in the ATP-CTP, which subject deals with the calculated capabilities of large jet aircraft?","choices":["Transport category aircraft performance","Float and seaplane handling","Soaring and gliding techniques"],"a":0,"src":{"doc":"14 CFR 61.156","ref":"Training requirements: ATP certification training program","url":"https://www.ecfr.gov/current/title-14/section-61.156","quote":"At least 14 hours of instruction on air carrier operations, including the following areas: ... (viii) Transport category aircraft performance. (14 CFR 61.156(a)(3)(viii))"}},
    {"id":"atp-062","acs":"ATP.I.F","q":"The ATP-CTP requires at least 6 hours of instruction on leadership, professional development, and what other related areas?","choices":["Maintenance logbook entries","Aircraft systems troubleshooting","Crew resource management and safety culture"],"a":2,"src":{"doc":"14 CFR 61.156","ref":"Training requirements: ATP certification training program","url":"https://www.ecfr.gov/current/title-14/section-61.156","quote":"At least 6 hours of instruction on leadership, professional development, crew resource management, and safety culture. (14 CFR 61.156(a)(4))"}},
    {"id":"atp-063","acs":"ATP.IV.B","q":"The ATP-CTP Level C or higher full flight simulator training must include which of the following recovery training areas?","choices":["Crosswind taxi only","Low energy states/stalls and upset recovery techniques","Normal cruise navigation only"],"a":1,"src":{"doc":"14 CFR 61.156","ref":"Training requirements: ATP certification training program","url":"https://www.ecfr.gov/current/title-14/section-61.156","quote":"The training must include the following areas: (i) Low energy states/stalls; (ii) Upset recovery techniques; and (iii) Adverse weather conditions, including icing, thunderstorms, and crosswinds with gusts. (14 CFR 61.156(b)(1))"}},
    {"id":"atp-064","acs":"ATP.I.D","q":"Compared with a straight wing, how does a swept wing develop lift as angle of attack increases?","choices":["Identically to a straight wing","With a much more gradual buildup of lift and a less well-defined maximum coefficient","With an abrupt, earlier peak in lift"],"a":1,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Ch 16 Transition to Jet-Powered Airplanes","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/airplane_handbook/17_afh_ch16.pdf","quote":"By contrast, the swept wing produces a much more gradual buildup of lift with a less well-defined maximum coefficient. (FAA-H-8083-3C, Ch 16)"}},
    {"id":"atp-065","acs":"ATP.VII.A","q":"At what altitude above the ground do the strong horizontal winds of a microburst occur?","choices":["Within a few hundred feet of the ground","Only above 10,000 feet","Only in the upper atmosphere"],"a":0,"src":{"doc":"AIM","ref":"Aeronautical Information Manual 7-1-24, Microbursts","url":"https://www.faa.gov/air_traffic/publications/atpubs/aim_html/chap7_section_1.html","quote":"These strong horizontal winds occur within a few hundred feet of the ground. (AIM 7-1-24)"}},
    {"id":"atp-066","acs":"ATP.VIII.A","q":"What aeronautical knowledge area, relevant to postflight weight and balance review, is listed for the ATP knowledge test?","choices":["Engine teardown inspection","Avionics software coding","Aircraft loading, weight and balance, use of charts, graphs, tables, formulas, and computations, and their effect on aircraft performance"],"a":2,"src":{"doc":"14 CFR 61.155","ref":"Aeronautical knowledge","url":"https://www.ecfr.gov/current/title-14/section-61.155","quote":"Aircraft loading, weight and balance, use of charts, graphs, tables, formulas, and computations, and their effect on aircraft performance. (14 CFR 61.155(c)(9))"}},
    {"id":"atp-067","acs":"ATP.I.F","q":"Which ATP aeronautical knowledge area addresses pilot judgment in the cockpit?","choices":["Ramp marshalling signals","Aircraft painting and finishing","Aeronautical decision making and judgment"],"a":2,"src":{"doc":"14 CFR 61.155","ref":"Aeronautical knowledge","url":"https://www.ecfr.gov/current/title-14/section-61.155","quote":"Aeronautical decision making and judgment. (14 CFR 61.155(c)(12))"}},
    {"id":"atp-068","acs":"ATP.VI.B","q":"The 40:1 obstacle clearance surface used to assess departure procedures provides what minimum clearance above non-penetrating objects when the standard 200 ft/NM gradient is flown?","choices":["A minimum of 100 ft/NM","A minimum of 24 ft/NM","A minimum of 48 ft/NM"],"a":2,"src":{"doc":"FAA-H-8083-16B","ref":"Instrument Procedures Handbook, Ch 1 Departure Procedures","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/instrument_procedures_handbook/FAA-H-8083-16B_Chapter_1.pdf","quote":"If no obstacles penetrate this 40:1 OCS, the standard 200 ft/NM climb gradient provides a minimum of 48 ft/NM of clearance above objects that do not penetrate the slope. (FAA-H-8083-16B, Ch 1)"}},
    {"id":"atp-069","acs":"ATP.III.J","q":"For a jet airplane takeoff, VR cannot be less than V1 or less than what multiple of VMCA?","choices":["1.05 times VMCA","1.3 times VMCA","1.5 times VMCA"],"a":0,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Ch 16 Transition to Jet-Powered Airplanes","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/airplane_handbook/17_afh_ch16.pdf","quote":"This speed cannot be less than V1 or less than 1.05 x VMCA (minimum control speed in the air). (FAA-H-8083-3C, Ch 16)"}},
    {"id":"atp-070","acs":"ATP.I.C","q":"Which ATP aeronautical knowledge area covers fronts, cloud formations, icing, and upper-air data?","choices":["Air traffic control radar maintenance","Runway pavement classification","Meteorology, including knowledge of and effects of fronts, frontal characteristics, cloud formations, icing, and upper-air data"],"a":2,"src":{"doc":"14 CFR 61.155","ref":"Aeronautical knowledge","url":"https://www.ecfr.gov/current/title-14/section-61.155","quote":"Meteorology, including knowledge of and effects of fronts, frontal characteristics, cloud formations, icing, and upper-air data. (14 CFR 61.155(c)(2))"}},
    {"id":"atp-071","acs":"ATP.I.G","q":"For an ATP certificate obtained under the reduced experience requirements of 14 CFR 61.160 (such as 21 years of age), which experience rule applies?","choices":["The reduced-hour pathways of 61.160","No experience is required","The 1,500-hour rule of 61.159"],"a":0,"src":{"doc":"14 CFR 61.153","ref":"Eligibility requirements: General","url":"https://www.ecfr.gov/current/title-14/section-61.153","quote":"For an airline transport pilot certificate obtained under the aeronautical experience requirements of section 61.160, be at least 21 years of age. (14 CFR 61.153(a)(2))"}},
    {"id":"atp-072","acs":"ATP.I.G","q":"A graduate with a Bachelor's degree with an aviation major from a qualifying institution may apply for an ATP multiengine certificate with a minimum of how many total hours under 61.160?","choices":["1,000 hours","750 hours","1,250 hours"],"a":0,"src":{"doc":"14 CFR 61.160","ref":"Aeronautical experience: airplane category restricted privileges","url":"https://www.ecfr.gov/current/title-14/section-61.160","quote":"A person may apply for an airline transport pilot certificate with an airplane category multiengine class rating ... with a minimum of 1,000 hours of total time as a pilot if the person: (1) Holds a Bachelor's degree with an aviation major. (14 CFR 61.160(b))"}},
    {"id":"atp-073","acs":"ATP.VI.A","q":"An applicant who credits certain simulator and substitution time under 61.159 receives an ATP certificate with what limitation?","choices":["Holder does not meet the pilot in command aeronautical experience requirements of ICAO","Day VFR only","Single-engine airplanes only"],"a":0,"src":{"doc":"14 CFR 61.159","ref":"Aeronautical experience: airplane category rating","url":"https://www.ecfr.gov/current/title-14/section-61.159","quote":"An applicant who credits time under paragraphs (b) through (d) of this section and section 61.51(f)(4) is issued an airline transport pilot certificate with the limitation 'Holder does not meet the pilot in command aeronautical experience requirements of ICAO.' (14 CFR 61.159(e))"}},
    {"id":"atp-074","acs":"ATP.V.C","q":"Why is angle of attack a more reliable parameter than airspeed for avoiding a stall?","choices":["Because AOA changes with weight while stall speed does not","Because an airplane can stall at any speed, but always stalls at the same critical AOA","Because airspeed indicators are unreliable"],"a":1,"src":{"doc":"FAA-H-8083-25C","ref":"Pilot's Handbook of Aeronautical Knowledge, Ch 5 Aerodynamics of Flight","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/phak/07_phak_ch5.pdf","quote":"Speed by itself is not a reliable parameter to avoid a stall. An airplane can stall at any speed. Angle of attack is a better parameter to use to avoid a stall. (FAA-H-8083-25C, Ch 5)"}},
    {"id":"atp-075","acs":"ATP.IV.A","q":"What is the approximate range of the critical angle of attack for most airplanes, depending on design?","choices":["Approximately 30 to 40 degrees","Approximately 16 to 20 degrees","Approximately 5 to 8 degrees"],"a":1,"src":{"doc":"FAA-H-8083-25C","ref":"Pilot's Handbook of Aeronautical Knowledge, Ch 5 Aerodynamics of Flight","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/phak/07_phak_ch5.pdf","quote":"This critical AOA varies from approximately 16 to 20 degrees depending on the aircraft's design. (FAA-H-8083-25C, Ch 5)"}},
    {"id":"atp-076","acs":"ATP.VIII.A","q":"Among the ATP-CTP air carrier operations academic topics, which addresses the procedures used while the aircraft is on the ground?","choices":["Oceanic navigation","Ground operations","High-altitude physiology only"],"a":1,"src":{"doc":"14 CFR 61.156","ref":"Training requirements: ATP certification training program","url":"https://www.ecfr.gov/current/title-14/section-61.156","quote":"At least 14 hours of instruction on air carrier operations, including the following areas: ... (vi) Ground operations. (14 CFR 61.156(a)(3)(vi))"}},
    {"id":"atp-077","acs":"ATP.VII.B","q":"For a jet takeoff, V1 also represents the minimum speed following a critical engine failure at VEF at which the pilot can do what?","choices":["Retract the landing gear safely","Reject the takeoff and stop within the runway","Continue the takeoff and achieve the required height above the takeoff surface within the takeoff distance"],"a":2,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Ch 16 Transition to Jet-Powered Airplanes","url":"https://www.faa.gov/sites/faa.gov/files/regulations_policies/handbooks_manuals/aviation/airplane_handbook/17_afh_ch16.pdf","quote":"It is also the minimum speed in the takeoff, following a failure of the critical engine at VEF, at which the pilot can continue the takeoff and achieve the required height above the takeoff surface within the takeoff distance. (FAA-H-8083-3C, Ch 16)"}},
    {"id":"atp-078","acs":"ATP.VI.A","q":"What aeronautical knowledge area covers principles of air navigation under instrument meteorological conditions in the NAS?","choices":["Marine navigation aids","Survival equipment maintenance","Principles of air navigation under instrument meteorological conditions in the National Airspace System"],"a":2,"src":{"doc":"14 CFR 61.155","ref":"Aeronautical knowledge","url":"https://www.ecfr.gov/current/title-14/section-61.155","quote":"Principles of air navigation under instrument meteorological conditions in the National Airspace System. (14 CFR 61.155(c)(7))"}}
  ]
};
